#include <iostream>
#include <string>
#include <vector>

class ResourceHandler {
private:
    std::vector<std::string> m_resource_status_vector;

public:
    ResourceHandler() {
        m_resource_status_vector.push_back("System Resource: Active and operational.");
        std::cout << "Resource acquired: " << m_resource_status_vector[0] << std::endl;
        std::cout << "Initialization complete." << std::endl;
    }

    ~ResourceHandler() {
        std::cout << "--- Resource Handler Destructor Initiated ---" << std::endl;
        if (!m_resource_status_vector.empty()) {
            std::cout << "STATUS UPDATE: The resource \"" << m_resource_status_vector[0] << "\" has been officially released." << std::endl;
        } else {
            std::cout << "STATUS UPDATE: No resource found to release." << std::endl;
        }
        std::cout << "--- Resource Handler Destructor Concluded ---" << std::endl;
    }
};

int main() {
    std::cout << "Main application started." << std::endl;
    {
        ResourceHandler my_complex_resource_handler_object;
        std::cout << "ResourceHandler object operational within its designated scope." << std::endl;
    }
    std::cout << "Main application finished." << std::endl;
    return 0;
}
